\frac{\partial u}{\partial t}=e^{-t} \frac{\partial^{2} u}{\partial x^{2}} \\
u(x, 0)=f(x)
\end{array}
$$
8.
$$
\begin{array}{l}
\frac{\partial^{2} u}{\partial t^{2}}=\frac{\partial^{4} u}{\partial x^{4}} \\
u(x, 0)=f(x)
\end{array}
$$
